import{_ as e,c as o,o as i,a8 as l}from"./chunks/framework.BrmF0WDH.js";const p=JSON.parse('{"title":"07-扩展点与新人落地建议","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/07-扩展点与新人落地建议/index.md","filePath":"onboarding/07-扩展点与新人落地建议/index.md","lastUpdated":1777649372000}'),r={name:"onboarding/07-扩展点与新人落地建议/index.md"};function t(d,a,c,h,n,s){return i(),o("div",null,a[0]||(a[0]=[l('<h1 id="_07-扩展点与新人落地建议" tabindex="1">07-扩展点与新人落地建议 <a class="header-anchor" href="#_07-扩展点与新人落地建议" aria-label="Permalink to &quot;07-扩展点与新人落地建议&quot;">​</a></h1><h2 id="新人第一次接需求-建议先判断改动属于哪一层" tabindex="1">新人第一次接需求，建议先判断改动属于哪一层 <a class="header-anchor" href="#新人第一次接需求-建议先判断改动属于哪一层" aria-label="Permalink to &quot;新人第一次接需求，建议先判断改动属于哪一层&quot;">​</a></h2><h3 id="_1-组件显示不对" tabindex="1">1. 组件显示不对 <a class="header-anchor" href="#_1-组件显示不对" aria-label="Permalink to &quot;1. 组件显示不对&quot;">​</a></h3><p>优先看：</p><ul><li><code>packages/ui</code></li><li><code>runtime/*</code></li><li><code>packages/core/src/utils.ts</code></li></ul><h3 id="_2-属性面板要新增配置项" tabindex="1">2. 属性面板要新增配置项 <a class="header-anchor" href="#_2-属性面板要新增配置项" aria-label="Permalink to &quot;2. 属性面板要新增配置项&quot;">​</a></h3><p>优先看：</p><ul><li><code>packages/ui/src/**/formSchema.ts</code></li><li><code>packages/ui/src/config.ts</code></li><li><code>packages/editor/src/services/props-service.ts</code></li></ul><h3 id="_3-拖拽、选中、缩放有问题" tabindex="1">3. 拖拽、选中、缩放有问题 <a class="header-anchor" href="#_3-拖拽、选中、缩放有问题" aria-label="Permalink to &quot;3. 拖拽、选中、缩放有问题&quot;">​</a></h3><p>优先看：</p><ul><li><code>packages/sandbox</code></li><li><code>packages/editor/src/components/layouts/sandbox/index.vue</code></li></ul><h3 id="_4-数据联动、模板表达式、条件显示有问题" tabindex="1">4. 数据联动、模板表达式、条件显示有问题 <a class="header-anchor" href="#_4-数据联动、模板表达式、条件显示有问题" aria-label="Permalink to &quot;4. 数据联动、模板表达式、条件显示有问题&quot;">​</a></h3><p>优先看：</p><ul><li><code>packages/core/src/node.ts</code></li><li><code>packages/data-source/src/utils/deps.ts</code></li><li><code>packages/data-source/src/data-source-manager.ts</code></li></ul><h3 id="_5-页面结构增删改有问题" tabindex="1">5. 页面结构增删改有问题 <a class="header-anchor" href="#_5-页面结构增删改有问题" aria-label="Permalink to &quot;5. 页面结构增删改有问题&quot;">​</a></h3><p>优先看：</p><ul><li><code>packages/editor/src/services/editor-service.ts</code></li><li><code>runtime/vue3-active/playground/App.vue</code></li></ul><h2 id="最值得先做的-3-个熟悉动作" tabindex="1">最值得先做的 3 个熟悉动作 <a class="header-anchor" href="#最值得先做的-3-个熟悉动作" aria-label="Permalink to &quot;最值得先做的 3 个熟悉动作&quot;">​</a></h2><h3 id="_1-跑通一次新增组件" tabindex="1">1. 跑通一次新增组件 <a class="header-anchor" href="#_1-跑通一次新增组件" aria-label="Permalink to &quot;1. 跑通一次新增组件&quot;">​</a></h3><p>建议从最简单的组件入手，例如 Button 或 Text，完整经历：</p><ul><li>左侧拖入</li><li>在 <code>root</code> 中出现新节点</li><li>sandbox 内渲染</li><li>属性面板修改</li><li>runtime 更新</li></ul><p>这是理解编辑器主链路最快的方法。</p><h3 id="_2-跑通一次数据源更新" tabindex="1">2. 跑通一次数据源更新 <a class="header-anchor" href="#_2-跑通一次数据源更新" aria-label="Permalink to &quot;2. 跑通一次数据源更新&quot;">​</a></h3><p>建议手动让某个 <code>base</code> 数据源字段变化，观察：</p><ul><li>依赖有没有被 track</li><li><code>trigger</code> 后哪些节点被命中</li><li>节点配置有没有重编译</li></ul><p>这是理解动态页面最重要的一步。</p><h3 id="_3-跑通一次组件扩展" tabindex="1">3. 跑通一次组件扩展 <a class="header-anchor" href="#_3-跑通一次组件扩展" aria-label="Permalink to &quot;3. 跑通一次组件扩展&quot;">​</a></h3><p>最小闭环通常是：</p><ol><li>新增运行时组件</li><li>新增 <code>formSchema</code></li><li>注册到组件导出和配置映射</li><li>在 playground 组件列表里露出</li></ol><p>这样你会真正知道“扩展点”在哪里，而不是只知道改哪一层 UI。</p><h2 id="当前工程里可以继续优化的点" tabindex="1">当前工程里可以继续优化的点 <a class="header-anchor" href="#当前工程里可以继续优化的点" aria-label="Permalink to &quot;当前工程里可以继续优化的点&quot;">​</a></h2><p>这部分不是挑毛病，而是帮助新人快速识别工程成熟度边界。</p><h3 id="_1-文档和代码存在一定偏差" tabindex="1">1. 文档和代码存在一定偏差 <a class="header-anchor" href="#_1-文档和代码存在一定偏差" aria-label="Permalink to &quot;1. 文档和代码存在一定偏差&quot;">​</a></h3><p>仓库里已有部分文档更偏概念介绍，和当前源码并不完全一一对应。以后继续补文档时，建议优先以代码为准。</p><h3 id="_2-数据依赖系统还比较原始" tabindex="1">2. 数据依赖系统还比较原始 <a class="header-anchor" href="#_2-数据依赖系统还比较原始" aria-label="Permalink to &quot;2. 数据依赖系统还比较原始&quot;">​</a></h3><p>当前实现可用，但离“声明式响应式引擎”还有距离，后续如果做复杂联动，这里会是重点演进点。</p><h3 id="_3-编辑器状态和-runtime-状态存在双端同步成本" tabindex="1">3. 编辑器状态和 runtime 状态存在双端同步成本 <a class="header-anchor" href="#_3-编辑器状态和-runtime-状态存在双端同步成本" aria-label="Permalink to &quot;3. 编辑器状态和 runtime 状态存在双端同步成本&quot;">​</a></h3><p>这套设计是必要的，但也意味着：</p><ul><li>某些 bug 会出现在两边状态不一致</li><li>调试时必须同时看编辑器和 iframe 内状态</li></ul><h3 id="_4-组件协议还可以进一步标准化" tabindex="1">4. 组件协议还可以进一步标准化 <a class="header-anchor" href="#_4-组件协议还可以进一步标准化" aria-label="Permalink to &quot;4. 组件协议还可以进一步标准化&quot;">​</a></h3><p>目前 <code>formSchema.ts</code>、<code>event.ts</code>、组件实现已经形成模式，但还没有完全收敛成统一规范文档。</p><h2 id="新人排障-checklist" tabindex="1">新人排障 checklist <a class="header-anchor" href="#新人排障-checklist" aria-label="Permalink to &quot;新人排障 checklist&quot;">​</a></h2><p>遇到问题时，建议固定按这个顺序排查：</p><ol><li>Schema 是否正确</li><li><code>EditorService</code> 是否正确回写 root</li><li>sandbox 是否把变更同步给 runtime</li><li>runtime 是否正确更新 <code>LowCodeRoot / LowCodeNode</code></li><li>UI 组件是否消费到了最终 config</li></ol><p>只要顺序不乱，绝大多数问题都能较快定位。</p><h2 id="推荐的第一周上手目标" tabindex="1">推荐的第一周上手目标 <a class="header-anchor" href="#推荐的第一周上手目标" aria-label="Permalink to &quot;推荐的第一周上手目标&quot;">​</a></h2><h3 id="第一天" tabindex="1">第一天 <a class="header-anchor" href="#第一天" aria-label="Permalink to &quot;第一天&quot;">​</a></h3><p>看完 <code>00</code>、<code>01</code>、<code>02</code>，能说清项目分层。</p><h3 id="第二天" tabindex="1">第二天 <a class="header-anchor" href="#第二天" aria-label="Permalink to &quot;第二天&quot;">​</a></h3><p>读 <code>03</code>、<code>04</code>，能跟着代码找到一次新增组件链路。</p><h3 id="第三天" tabindex="1">第三天 <a class="header-anchor" href="#第三天" aria-label="Permalink to &quot;第三天&quot;">​</a></h3><p>读 <code>05</code>、<code>06</code>，能解释一次数据更新如何驱动页面变化。</p><h3 id="第四到第五天" tabindex="1">第四到第五天 <a class="header-anchor" href="#第四到第五天" aria-label="Permalink to &quot;第四到第五天&quot;">​</a></h3><p>自己完成一个小改动，例如：</p><ul><li>给现有组件加一个属性项</li><li>给现有数据源方法补一段逻辑</li><li>调整一个拖拽/选中体验问题</li></ul><h2 id="收尾建议" tabindex="1">收尾建议 <a class="header-anchor" href="#收尾建议" aria-label="Permalink to &quot;收尾建议&quot;">​</a></h2><p>新人不要一开始试图把所有包都读完。</p><p>先抓主链路：</p><p><code>Playground -&gt; EditorService -&gt; Sandbox -&gt; Runtime -&gt; Core -&gt; UI</code></p><p>再抓动态链路：</p><p><code>DataSource -&gt; track/trigger -&gt; LowCodeNode -&gt; 页面更新</code></p><p>能把这两条线串起来，项目就算真正入门了。</p>',62)]))}const b=e(r,[["render",t]]);export{p as __pageData,b as default};
